UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('6b1bc9f1-933b-4475-a4ff-4797573cc90e'::uuid, 'La toux du fumeur irrite la gorge, ces pastilles forment un film protecteur sur la muqueuse pour apaiser l''irritation.'),('250fc64f-6400-4fe0-8b19-cd92a097ad6d'::uuid, 'La toux du fumeur produit un mucus épais, ce sirop fluidifie les sécrétions bronchiques pour faciliter leur expectoration.'),('96c29143-1ab6-48dc-8152-8709197a249e'::uuid, 'La dépendance à la nicotine entretient la toux du fumeur, ces substituts réduisent le besoin en nicotine pour aider au sevrage.'),('bccbdac9-d251-4e77-9782-f346de5a8bc0'::uuid, 'La toux grasse est due à l''accumulation de mucus, ce sirop fluidifie les sécrétions bronchiques pour faciliter leur évacuation.'),('546d824d-6722-4788-a7f2-86d9dd35e178'::uuid, 'La toux grasse peut être associée à des sécrétions nasales, ce spray rince les fosses nasales pour éliminer le mucus.'),('e7d90276-9f6e-46fe-b01b-366a0b6a1b64'::uuid, 'La toux grasse peut s''accompagner de congestion nasale, ce spray réduit l''œdème de la muqueuse nasale pour libérer les voies respiratoires.'),('991813ac-0910-48c3-8dae-1a4d5ae22e84'::uuid, 'Une toux productive est souvent liée à la congestion nasale, ce spray hypertonique diminue l''œdème de la muqueuse pour faciliter la respiration.'),('0217893f-8b07-4b9d-87bb-2504309366ca'::uuid, 'Une toux productive est souvent liée à la congestion nasale, ce spray hypertonique diminue l''œdème de la muqueuse pour faciliter la respiration.'),('d0b9f75b-3994-4543-a0a9-1ce141ed2146'::uuid, 'Une toux productive est souvent liée à la congestion nasale, ce spray hypertonique diminue l''œdème de la muqueuse pour faciliter la respiration.'),('836022a1-75c1-4f34-b165-87cf7999bbc8'::uuid, 'La toux sèche irrite la gorge, ces pastilles forment un film protecteur sur la muqueuse pour réduire l''irritation et la toux.'),('bb84b4d2-3f21-41f0-9eab-37b96b593586'::uuid, 'La toux sèche est due à une irritation de la muqueuse, le miel de Manuka crée une couche protectrice et apaise la gorge.'),('d874ecfe-daab-4626-9d79-156c91778cbd'::uuid, 'La toux sèche irrite la gorge, ces pastilles libèrent des agents apaisants qui hydratent la muqueuse et calment l''irritation.'),('9aa49903-f5c2-4755-8968-2758a6570829'::uuid, 'Certains traitements peuvent affecter l''absorption des vitamines; la vitamine D3 soutient la minéralisation osseuse et le système immunitaire.'),('4e9bd974-1096-4780-be05-96179747fd6f'::uuid, 'Les acides biliaires peuvent influencer la digestion, le magnésium B6 aide à réduire l''impact sur le système nerveux et la fatigue.'),('dfa2fb05-893d-453d-b9ec-99da9bb1b270'::uuid, 'Les traitements peuvent perturber la flore intestinale, les probiotiques rééquilibrent le microbiome digestif pour améliorer la digestion globale.'),('ac89437d-238b-47cb-88d0-e49baf4996e4'::uuid, 'Certains traitements peuvent affecter les niveaux de vitamine D, la D3 soutient l''intégrité osseuse et renforce le système immunitaire.'),('80f52e1b-4e6c-4d60-be10-0c19696150e9'::uuid, 'Les agonistes dopaminergiques peuvent augmenter la fatigue, le magnésium B6 contribue au fonctionnement neuromusculaire et réduit l''épuisement.'),('08c28730-f60d-480f-9ead-6c854d9802f1'::uuid, 'Les médicaments peuvent altérer la microflore intestinale, les probiotiques maintiennent l''équilibre digestif et soutiennent l''immunité.'),('736920e4-4fbb-4942-a5a7-2ac02ecddb72'::uuid, 'Le sevrage tabagique peut affaiblir l''immunité, la vitamine D3 1000UI soutient les défenses naturelles de l''organisme.'),('226d446a-6051-4137-9bf9-24442919923b'::uuid, 'Le sevrage tabagique peut générer du stress et de la fatigue, le magnésium B6 aide à la régulation du système nerveux.'),('b514a5d4-62c1-4ad2-817f-5d0315b9a91a'::uuid, 'Le stress du sevrage peut déséquilibrer la flore intestinale, les probiotiques maintiennent une digestion saine et l''immunité.'),('dbd5a8cb-30b6-442b-8ca9-579defbb6c1f'::uuid, 'Les AINS peuvent provoquer des douleurs musculaires, l''arnica topique aide à apaiser l''inflammation locale.'),('eaba5c3f-9f17-4591-9a11-e723e850a009'::uuid, 'Les AINS peuvent entraîner des tensions musculaires, le magnésium B6 contribue à la fonction musculaire et réduit les crampes.'),('a67fe52f-f5b5-4af3-a048-f9bc258c6f82'::uuid, 'Les raideurs musculaires sont fréquentes, l''application de chaleur permet de détendre les tissus et apaiser la douleur.'),('9c197716-c0d2-44e5-b711-5e803af4f2e5'::uuid, 'L''inflammation locale peut être soulagée, l''arnica aide à réduire l''œdème et les ecchymoses.'),('0e3191ab-1dc5-4b21-8873-a1a8265722f0'::uuid, 'Les AINS topiques traitent l''inflammation locale, l''arnica aide à réduire la douleur et les gonflements.'),('fbb3776b-172e-431e-87a7-c83faf417a73'::uuid, 'L''application d''AINS peut provoquer une irritation locale, l''arnica aide à apaiser la peau et réduire l''inflammation.'),('1decd8ed-170b-4b75-ba3e-09ac9c4b059b'::uuid, 'Certains traitements peuvent favoriser les infections urinaires, l''extrait de cranberry soutient la santé des voies urinaires.'),('05dccd08-3423-4818-9a2b-9549060cad96'::uuid, 'Les alpha-bloquants peuvent perturber la flore intime, les probiotiques contribuent à l''équilibre du microbiome urogénital.'),('efc17243-0c39-4913-8837-3b5b9712dc80'::uuid, 'Certains traitements affectent la muqueuse urinaire, le D-Mannose aide à protéger et maintenir son intégrité.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;